// Store functions as values in an array
const pipeline = [
  (x) => x.trim(),
  (x) => x.toLowerCase(),
  (x) => x.replace(/\s+/g, '-'),
];

// Pass and return functions — run the pipeline
function process(input, steps) {
  return steps.reduce((result, step) => step(result), input);
}

console.log(process('  Hello World  ', pipeline)); // 'hello-world'

// Store functions in an object (strategy pattern)
const formatters = {
  currency: (n) => `$${n.toFixed(2)}`,
  percent: (n) => `${(n * 100).toFixed(1)}%`,
};

console.log(formatters.currency(9.5));  // '$9.50'
console.log(formatters.percent(0.175)); // '17.5%'

